import * as React from "react"
import { cn } from "@/lib/utils"

interface OrbitItem { content: React.ReactNode; radius?: number; duration?: number; offset?: number }

interface OrbitAnimationProps {
  center?: React.ReactNode
  items: OrbitItem[]
  size?: number
  className?: string
}

export function OrbitAnimation({ center, items, size = 280, className }: OrbitAnimationProps) {
  return (
    <div
      className={cn("relative flex items-center justify-center", className)}
      style={{ width: size, height: size }}
    >
      {/* Rings */}
      {Array.from(new Set(items.map(i => i.radius ?? 80))).map(r => (
        <div
          key={r}
          className="absolute rounded-full border border-white/[0.06]"
          style={{ width: r * 2, height: r * 2 }}
        />
      ))}
      {/* Center */}
      {center && (
        <div className="relative z-10 flex items-center justify-center">{center}</div>
      )}
      {/* Orbiting items */}
      {items.map((item, i) => {
        const r = item.radius ?? 80 + i * 40
        const dur = item.duration ?? 10 + i * 3
        const off = item.offset ?? (i * 360) / items.length
        return (
          <div
            key={i}
            className="absolute inset-0 flex items-center justify-center"
            style={{ animation: `orbit ${dur}s linear infinite`, animationDelay: `${-(off / 360) * dur}s` }}
          >
            <div style={{ transform: `translateY(-${r}px)` }}>{item.content}</div>
          </div>
        )
      })}
      <style>{`
        @keyframes orbit { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
      `}</style>
    </div>
  )
}
